mapper.select:
SELECT
    /* 今日有效预约数（已支付 + 待支付 + 已就诊） */
    (SELECT COUNT(*)
     FROM appointment
     WHERE DATE(created_at) = CURDATE()
       AND status IN (0, 1, 2)
    ) AS todayAppointments,

    /* 今日已支付数 */
    (SELECT COUNT(*)
     FROM appointment
     WHERE DATE(created_at) = CURDATE()
       AND status = 1
    ) AS todayPaid,

    /* 今日收入 = 今日支付数 * 固定单价（后续可改为 schedule.price） */
    (SELECT COUNT(*) * #{defaultPrice}
     FROM appointment
     WHERE DATE(created_at) = CURDATE()
       AND status = 1
    ) AS todayIncome,

    /* 历史有效预约数 */
    (SELECT COUNT(*)
     FROM appointment
     WHERE status IN (0, 1, 2)
    ) AS totalAppointments,

    /* 历史总收入 = 历史支付数 * 固定单价 */
    (SELECT COUNT(*) * #{defaultPrice}
     FROM appointment
     WHERE status = 1
    ) AS totalIncome,

    /* 总患者数 */
    (SELECT COUNT(*) FROM patient WHERE status = 1) AS totalPatients,

    /* 总医生数（审核通过且启用） */
    (SELECT COUNT(*)
     FROM doctor d
              INNER JOIN doctor_audit da ON d.id = da.doctor_id
     WHERE d.status = 1 AND da.audit_status = 1
    ) AS totalDoctors,

    /* 总评价数（已发布） */
    (SELECT COUNT(*) FROM evaluation WHERE status = 1) AS totalEvaluations
FROM DUAL
